#include <stdio.h>
#include <stdlib.h>

// Structure for max heap node
typedef struct Node {
    int count;
} Node;

// Function to swap two nodes
void swap(Node *a, Node *b) {
    Node temp = *a;
    *a = *b;
    *b = temp;
}

// Function to heapify the max heap
void heapify(Node *heap, int size, int index) {
    int largest = index;
    int left = 2 * index + 1;
    int right = 2 * index + 2;

    if (left < size && heap[left].count > heap[largest].count) {
        largest = left;
    }

    if (right < size && heap[right].count > heap[largest].count) {
        largest = right;
    }

    if (largest != index) {
        swap(&heap[index], &heap[largest]);
        heapify(heap, size, largest);
    }
}

// Function to extract the maximum element from the max heap
Node extractMax(Node *heap, int *size) {
    Node max = heap[0];
    heap[0] = heap[*size - 1];
    (*size)--;
    heapify(heap, *size, 0);
    return max;
}

// Function to insert a new element into the max heap
void insert(Node *heap, int *size, Node node) {
    heap[*size] = node;
    (*size)++;
    int index = *size - 1;

    while (index > 0 && heap[(index - 1) / 2].count < heap[index].count) {
        swap(&heap[index], &heap[(index - 1) / 2]);
        index = (index - 1) / 2;
    }
}

// Function to calculate the least interval
int leastInterval(char *tasks, int tasksSize, int n) {
    int freq[26] = {0};
    for (int i = 0; i < tasksSize; i++) {
        freq[tasks[i] - 'A']++;
    }

    Node *heap = (Node *)malloc(26 * sizeof(Node));
    int size = 0;
    for (int i = 0; i < 26; i++) {
        if (freq[i] > 0) {
            Node node;
            node.count = freq[i];
            insert(heap, &size, node);
        }
    }

    int time = 0;
    while (size > 0) {
        Node temp[26];
        int tempSize = 0;
        for (int i = 0; i <= n; i++) {
            if (size > 0) {
                Node node = extractMax(heap, &size);
                if (node.count > 1) {
                    temp[tempSize].count = node.count - 1;
                    tempSize++;
                }
            }
            time++;
        }
        for (int i = 0; i < tempSize; i++) {
            insert(heap, &size, temp[i]);
        }
    }
    return time;
}

// Driver code
int main() {
    char tasks[] = {'A', 'A', 'A', 'B', 'B', 'B'};
    int n = 2;
    printf("%d\n", leastInterval(tasks, 6, n));
    return 0;
}

